sql:
SELECT MAX(household_size) AS largest_household_size
FROM households
WHERE household_type = 'Single';

SELECT household_id, address_id, household_size, income, household_type, last_updated
FROM households
WHERE household_size = 1 AND income > (SELECT AVG(income) FROM households);

external_knowledge:
- 'mature folks' refers to people aged between 18 and 55; 
- 'larger families' means households with more than 3 members; 
- 'earn more than a decent living' refers to an annual household income greater than $100,000.
